86:                                             envoy::service::discovery::v3::DiscoveryResponse>>(
87:         /*primary_stream_creator=*/
88:         [&grpc_mux_context](
89:             GrpcStreamCallbacks<envoy::service::discovery::v3::DiscoveryResponse>* callbacks)
90:             -> GrpcStreamInterfacePtr<envoy::service::discovery::v3::DiscoveryRequest,
91:                                       envoy::service::discovery::v3::DiscoveryResponse> {
92:           return std::make_unique<GrpcStream<envoy::service::discovery::v3::DiscoveryRequest,
93:                                              envoy::service::discovery::v3::DiscoveryResponse>>(
94:               callbacks, std::move(grpc_mux_context.async_client_),
95:               grpc_mux_context.service_method_, grpc_mux_context.dispatcher_,
96:               grpc_mux_context.scope_, std::move(grpc_mux_context.backoff_strategy_),
97:               grpc_mux_context.rate_limit_settings_);
98:         },
99:         /*failover_stream_creator=*/
100:         grpc_mux_context.failover_async_client_
101:             ? absl::make_optional(
102:                   [&grpc_mux_context](
103:                       GrpcStreamCallbacks<envoy::service::discovery::v3::DiscoveryResponse>*
104:                           callbacks)
105:                       -> GrpcStreamInterfacePtr<envoy::service::discovery::v3::DiscoveryRequest,
106:                                                 envoy::service::discovery::v3::DiscoveryResponse> {
107:                     return std::make_unique<
108:                         GrpcStream<envoy::service::discovery::v3::DiscoveryRequest,
109:                                    envoy::service::discovery::v3::DiscoveryResponse>>(
110:                         callbacks, std::move(grpc_mux_context.failover_async_client_),
111:                         grpc_mux_context.service_method_, grpc_mux_context.dispatcher_,
112:                         grpc_mux_context.scope_,
113:                         // TODO(adisuissa): the backoff strategy for the failover should
114:                         // be the same as the primary source.
115:                         std::make_unique<FixedBackOffStrategy>(
116:                             GrpcMuxFailover<envoy::service::discovery::v3::DiscoveryRequest,
117:                                             envoy::service::discovery::v3::DiscoveryResponse>::
118:                                 DefaultFailoverBackoffMilliseconds),
119:                         grpc_mux_context.rate_limit_settings_);
120:                   })
121:             : absl::nullopt,
122:         /*grpc_mux_callbacks=*/*this,
123:         /*dispatch=*/grpc_mux_context.dispatcher_);
124:   }
125:   return std::make_unique<GrpcStream<envoy::service::discovery::v3::DiscoveryRequest,
126:                                      envoy::service::discovery::v3::DiscoveryResponse>>(
127:       this, std::move(grpc_mux_context.async_client_), grpc_mux_context.service_method_,
