191: void GrpcMuxImpl::clearNonce() {
192:   // Iterate over all api_states (for each type_url), and clear its nonce.
193:   for (auto& [type_url, api_state] : api_state_) {
194:     if (api_state) {
195:       api_state->request_.clear_response_nonce();
196:     }
197:   }
