563: void GrpcMuxImpl::expiryCallback(absl::string_view type_url,
564:                                  const std::vector<std::string>& expired) {
565:   // The TtlManager triggers a callback with a list of all the expired elements, which we need
566:   // to compare against the various watched resources to return the subset that each watch is
567:   // subscribed to.
568: 
569:   // We convert the incoming list into a set in order to more efficiently perform this
570:   // comparison when there are a lot of watches.
571:   absl::flat_hash_set<std::string> all_expired;
572:   all_expired.insert(expired.begin(), expired.end());
573: 
574:   // Note: We can blindly dereference the lookup here since the only time we call this is in a
575:   // callback that is created at the same time as we insert the ApiState for this type.
576:   for (auto watch : api_state_.find(type_url)->second->watches_) {
577:     Protobuf::RepeatedPtrField<std::string> found_resources_for_watch;
578: 
579:     for (const auto& resource : expired) {
580:       if (all_expired.find(resource) != all_expired.end()) {
581:         found_resources_for_watch.Add(std::string(resource));
582:       }
583:     }
584: 
585:     THROW_IF_NOT_OK(watch->callbacks_.onConfigUpdate({}, found_resources_for_watch, ""));
586:   }
587: }
588: 
589: GrpcMuxImpl::ApiState& GrpcMuxImpl::apiStateFor(absl::string_view type_url) {
590:   auto itr = api_state_.find(type_url);
591:   if (itr == api_state_.end()) {
592:     api_state_.emplace(
593:         type_url, std::make_unique<ApiState>(dispatcher_, [this, type_url](const auto& expired) {
594:           expiryCallback(type_url, expired);
595:         }));
596:   }
597: 
598:   return *api_state_.find(type_url)->second;
599: }
600: 
601: void GrpcMuxImpl::drainRequests() {
602:   while (!request_queue_->empty() && grpc_stream_->checkRateLimitAllowsDrain()) {
603:     // Process the request, if rate limiting is not enabled at all or if it is under rate limit.
604:     sendDiscoveryRequest(request_queue_->front());
605:     request_queue_->pop();
606:   }
607:   grpc_stream_->maybeUpdateQueueSizeStat(request_queue_->size());
608: }
