610: // A factory class for creating GrpcMuxImpl so it does not have to be
611: // hard-compiled into cluster_manager_impl.cc
612: class GrpcMuxFactory : public MuxFactory {
613: public:
614:   std::string name() const override { return "envoy.config_mux.grpc_mux_factory"; }
615:   void shutdownAll() override { return GrpcMuxImpl::shutdownAll(); }
616:   std::shared_ptr<GrpcMux>
617:   create(Grpc::RawAsyncClientPtr&& async_client, Grpc::RawAsyncClientPtr&& failover_async_client,
618:          Event::Dispatcher& dispatcher, Random::RandomGenerator&, Stats::Scope& scope,
619:          const envoy::config::core::v3::ApiConfigSource& ads_config,
620:          const LocalInfo::LocalInfo& local_info, CustomConfigValidatorsPtr&& config_validators,
621:          BackOffStrategyPtr&& backoff_strategy, XdsConfigTrackerOptRef xds_config_tracker,
622:          XdsResourcesDelegateOptRef xds_resources_delegate, bool use_eds_resources_cache) override {
623:     absl::StatusOr<RateLimitSettings> rate_limit_settings_or_error =
624:         Utility::parseRateLimitSettings(ads_config);
625:     THROW_IF_STATUS_NOT_OK(rate_limit_settings_or_error, throw);
626:     GrpcMuxContext grpc_mux_context{
627:         /*async_client_=*/std::move(async_client),
628:         /*failover_async_client_=*/std::move(failover_async_client),
629:         /*dispatcher_=*/dispatcher,
630:         /*service_method_=*/
631:         *Protobuf::DescriptorPool::generated_pool()->FindMethodByName(
632:             "envoy.service.discovery.v3.AggregatedDiscoveryService.StreamAggregatedResources"),
633:         /*local_info_=*/local_info,
634:         /*rate_limit_settings_=*/rate_limit_settings_or_error.value(),
635:         /*scope_=*/scope,
636:         /*config_validators_=*/std::move(config_validators),
637:         /*xds_resources_delegate_=*/xds_resources_delegate,
638:         /*xds_config_tracker_=*/xds_config_tracker,
639:         /*backoff_strategy_=*/std::move(backoff_strategy),
640:         /*target_xds_authority_=*/Config::Utility::getGrpcControlPlane(ads_config).value_or(""),
641:         /*eds_resources_cache_=*/
642:         (use_eds_resources_cache &&
643:          Runtime::runtimeFeatureEnabled("envoy.restart_features.use_eds_cache_for_ads"))
644:             ? std::make_unique<EdsResourcesCacheImpl>(dispatcher)
645:             : nullptr};
646:     return std::make_shared<Config::GrpcMuxImpl>(grpc_mux_context,
647:                                                  ads_config.set_node_on_first_message_only());
648:   }
649: };
