148: void LdsApiImpl::onConfigUpdateFailed(Envoy::Config::ConfigUpdateFailureReason reason,
149:                                       const EnvoyException*) {
150:   ASSERT(Envoy::Config::ConfigUpdateFailureReason::ConnectionFailure != reason);
151:   // We need to allow server startup to continue, even if we have a bad
152:   // config.
153:   init_target_.ready();
154: }
