40: absl::Status CdsApiImpl::onConfigUpdate(const std::vector<Config::DecodedResourceRef>& resources,
41:                                         const std::string& version_info) {
42:   auto all_existing_clusters = cm_.clusters();
43:   // Exclude the clusters which CDS wants to add.
44:   for (const auto& resource : resources) {
45:     all_existing_clusters.active_clusters_.erase(resource.get().name());
46:     all_existing_clusters.warming_clusters_.erase(resource.get().name());
47:   }
48:   Protobuf::RepeatedPtrField<std::string> to_remove_repeated;
49:   for (const auto& [cluster_name, _] : all_existing_clusters.active_clusters_) {
50:     UNREFERENCED_PARAMETER(_);
51:     *to_remove_repeated.Add() = cluster_name;
52:   }
53:   for (const auto& [cluster_name, _] : all_existing_clusters.warming_clusters_) {
54:     UNREFERENCED_PARAMETER(_);
55:     // Do not add the cluster twice when the cluster is both active and warming.
56:     if (!all_existing_clusters.active_clusters_.contains(cluster_name)) {
57:       *to_remove_repeated.Add() = cluster_name;
58:     }
59:   }
60:   return onConfigUpdate(resources, to_remove_repeated, version_info);
61: }
